const sanitizeColor = (val: string | null | undefined, fallback: string) => {
  if (!val || !/^#[0-9A-Fa-f]{6}$|^[a-zA-Z]+$/.test(val)) return fallback;
  return val;
};

async headers() {
  return [{
    source: '/(.*)',
    headers: [{ key: 'Content-Security-Policy', value: "default-src 'self'; style-src 'self' 'unsafe-inline'; script-src 'self'" }]
  }];
}
